import React, { useState, useEffect } from 'react';
import { taskAPI } from '../api';

const STATUS_COLORS = { PENDING: '#FF9800', IN_PROGRESS: '#1565C0', COMPLETED: '#2E7D32' };
const PRIORITY_COLORS = { HIGH: '#C62828', MEDIUM: '#E65100', LOW: '#6A1B9A' };

export default function TaskTracker() {
  const [tasks, setTasks] = useState([]);
  const [stats, setStats] = useState({ pending: 0, inProgress: 0, completed: 0 });
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [filterStatus, setFilterStatus] = useState('');
  const [form, setForm] = useState({ title: '', description: '', priority: 'MEDIUM', cropName: '', dueDate: '' });

  useEffect(() => { fetchTasks(); }, [filterStatus]);

  const fetchTasks = async () => {
    setLoading(true);
    try {
      const res = await taskAPI.getAll(filterStatus);
      setTasks(res.data.tasks || []);
      setStats(res.data.stats || {});
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const createTask = async (e) => {
    e.preventDefault();
    try {
      await taskAPI.create({ ...form, status: 'PENDING' });
      setForm({ title: '', description: '', priority: 'MEDIUM', cropName: '', dueDate: '' });
      setShowForm(false);
      fetchTasks();
    } catch (e) { alert('Failed to create task'); }
  };

  const updateStatus = async (id, status) => {
    try {
      await taskAPI.updateStatus(id, status);
      fetchTasks();
    } catch (e) { alert('Failed to update task'); }
  };

  const deleteTask = async (id) => {
    if (!window.confirm('Delete this task?')) return;
    try {
      await taskAPI.delete(id);
      fetchTasks();
    } catch (e) { alert('Failed to delete task'); }
  };

  const NEXT_STATUS = { PENDING: 'IN_PROGRESS', IN_PROGRESS: 'COMPLETED', COMPLETED: 'PENDING' };
  const STATUS_LABEL = { PENDING: '▶️ Start', IN_PROGRESS: '✅ Complete', COMPLETED: '🔄 Reset' };

  return (
    <div>
      {/* Stats */}
      <div style={styles.statsRow}>
        {[['Pending', stats.pending, '#FF9800', '📋'], ['In Progress', stats.inProgress, '#1565C0', '⚙️'], ['Completed', stats.completed, '#2E7D32', '✅']].map(([label, count, color, icon]) => (
          <div key={label} style={{ ...styles.statCard, borderTop: `4px solid ${color}` }}>
            <div style={styles.statIcon}>{icon}</div>
            <div style={{ ...styles.statCount, color }}>{count || 0}</div>
            <div style={styles.statLabel}>{label}</div>
          </div>
        ))}
      </div>

      {/* Toolbar */}
      <div style={styles.toolbar}>
        <div style={styles.filterBtns}>
          {[['', 'All'], ['PENDING', 'Pending'], ['IN_PROGRESS', 'In Progress'], ['COMPLETED', 'Completed']].map(([val, label]) => (
            <button key={val} style={{ ...styles.filterBtn, ...(filterStatus === val ? styles.filterBtnActive : {}) }}
              onClick={() => setFilterStatus(val)}>{label}</button>
          ))}
        </div>
        <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
          {showForm ? '✕ Cancel' : '+ Add Task'}
        </button>
      </div>

      {/* Add Task Form */}
      {showForm && (
        <div style={styles.formCard}>
          <div style={styles.formTitle}>📝 Add New Farm Task</div>
          <form onSubmit={createTask}>
            <div style={{ display: 'flex', gap: 14 }}>
              <div className="form-group" style={{ flex: 2 }}>
                <label>Task Title *</label>
                <input value={form.title} onChange={(e) => setForm(p => ({...p, title: e.target.value}))} placeholder="e.g. Apply fertilizer to paddy field" required />
              </div>
              <div className="form-group" style={{ flex: 1 }}>
                <label>Crop Name</label>
                <input value={form.cropName} onChange={(e) => setForm(p => ({...p, cropName: e.target.value}))} placeholder="Rice, Cotton..." />
              </div>
            </div>
            <div className="form-group">
              <label>Description</label>
              <textarea value={form.description} onChange={(e) => setForm(p => ({...p, description: e.target.value}))} rows={2} style={{resize:'none'}} placeholder="Additional notes..." />
            </div>
            <div style={{ display: 'flex', gap: 14 }}>
              <div className="form-group" style={{ flex: 1 }}>
                <label>Priority</label>
                <select value={form.priority} onChange={(e) => setForm(p => ({...p, priority: e.target.value}))}>
                  <option value="HIGH">🔴 High</option>
                  <option value="MEDIUM">🟡 Medium</option>
                  <option value="LOW">🟢 Low</option>
                </select>
              </div>
              <div className="form-group" style={{ flex: 1 }}>
                <label>Due Date</label>
                <input type="date" value={form.dueDate} onChange={(e) => setForm(p => ({...p, dueDate: e.target.value}))} />
              </div>
              <button className="btn btn-primary" type="submit" style={{ alignSelf: 'flex-end', height: 42 }}>
                ✅ Add Task
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Task List */}
      {loading ? (
        <div style={{ textAlign: 'center', padding: 40 }}>
          <div className="spinner" style={{width:36,height:36,margin:'0 auto'}} />
        </div>
      ) : tasks.length === 0 ? (
        <div style={styles.empty}>
          <div style={{ fontSize: 48, marginBottom: 12 }}>📋</div>
          <div style={styles.emptyText}>No tasks yet. Add your first farming task!</div>
        </div>
      ) : (
        <div style={styles.taskList}>
          {tasks.map((task) => (
            <div key={task.id} style={{ ...styles.taskCard, borderLeft: `4px solid ${STATUS_COLORS[task.status] || '#9E9E9E'}` }}>
              <div style={styles.taskTop}>
                <div style={styles.taskTitle}>{task.title}</div>
                <div style={styles.taskMeta}>
                  {task.cropName && <span style={styles.cropTag}>🌱 {task.cropName}</span>}
                  <span className="badge" style={{ background: PRIORITY_COLORS[task.priority] + '22', color: PRIORITY_COLORS[task.priority] }}>
                    {task.priority}
                  </span>
                  <span className="badge" style={{ background: STATUS_COLORS[task.status] + '22', color: STATUS_COLORS[task.status] }}>
                    {task.status?.replace('_', ' ')}
                  </span>
                </div>
              </div>
              {task.description && <div style={styles.taskDesc}>{task.description}</div>}
              {task.dueDate && <div style={styles.taskDue}>📅 Due: {new Date(task.dueDate).toLocaleDateString()}</div>}
              <div style={styles.taskActions}>
                <button className="btn btn-outline" style={{ fontSize: '0.8rem', padding: '5px 12px' }}
                  onClick={() => updateStatus(task.id, NEXT_STATUS[task.status])}>
                  {STATUS_LABEL[task.status]}
                </button>
                <button className="btn btn-danger" style={{ fontSize: '0.8rem', padding: '5px 12px' }}
                  onClick={() => deleteTask(task.id)}>
                  🗑️ Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

